import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { Oportunidade } from '../types';

const DashboardInstituicaoContratante: React.FC = () => {
  const { user } = useAuth();
  const [oportunidades, setOportunidades] = useState<Oportunidade[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchOportunidades = async () => {
      try {
        setLoading(true);
        const response = await fetch('/api/oportunidades', {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('token')}`
          }
        });

        if (!response.ok) {
          throw new Error('Erro ao carregar oportunidades');
        }

        const data = await response.json();
        setOportunidades(data);
        setLoading(false);
      } catch (error) {
        console.error('Erro:', error);
        setError('Erro ao carregar dados. Por favor, tente novamente.');
        setLoading(false);
      }
    };

    fetchOportunidades();
  }, []);

  const handleNovaOportunidade = () => {
    navigate('/instituicao-contratante/oportunidades/nova');
  };

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-cursor-text-primary">Dashboard da Instituição Contratante</h1>
        <div className="text-sm text-cursor-text-secondary">
          Bem-vindo(a), <span className="font-medium">{user?.nome}</span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="bg-white rounded-lg shadow p-6">
          <h2 className="text-lg font-semibold mb-2">Oportunidades Ativas</h2>
          <p className="text-3xl font-bold text-cursor-primary">
            {oportunidades.filter(o => o.status === 'Aberta').length}
          </p>
          <Link to="/instituicao-contratante/oportunidades" className="text-cursor-primary text-sm mt-2 inline-block hover:underline">
            Ver todas
          </Link>
        </div>

        <div className="bg-white rounded-lg shadow p-6">
          <h2 className="text-lg font-semibold mb-2">Total de Recomendações</h2>
          <p className="text-3xl font-bold text-cursor-primary">
            {oportunidades.reduce((acc, o) => acc + (o.total_recomendacoes || 0), 0)}
          </p>
        </div>

        <div className="bg-white rounded-lg shadow p-6">
          <h2 className="text-lg font-semibold mb-2">Jovens Contratados</h2>
          <p className="text-3xl font-bold text-cursor-primary">-</p>
        </div>
      </div>

      <div className="bg-white rounded-lg shadow mb-8">
        <div className="p-4 border-b border-gray-200 flex justify-between items-center">
          <h2 className="text-lg font-semibold">Oportunidades Recentes</h2>
          <button 
            onClick={handleNovaOportunidade}
            className="text-sm text-cursor-primary hover:underline flex items-center"
          >
            <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
            Nova Oportunidade
          </button>
        </div>
        <div className="p-4">
          {loading ? (
            <div className="text-center py-4">Carregando...</div>
          ) : error ? (
            <div className="text-center py-4 text-red-500">{error}</div>
          ) : oportunidades.length === 0 ? (
            <div className="text-center py-4 text-cursor-text-secondary">
              Nenhuma oportunidade cadastrada. 
              <button 
                onClick={handleNovaOportunidade}
                className="text-cursor-primary ml-2 hover:underline"
              >
                Criar oportunidade
              </button>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Título</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Tipo</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Recomendações</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Ações</th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {oportunidades.slice(0, 5).map(oportunidade => (
                    <tr key={oportunidade.id}>
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-cursor-text-primary">{oportunidade.titulo}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-cursor-text-secondary">{oportunidade.tipo}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm">
                        <span className={`px-2 py-1 text-xs rounded-full ${
                          oportunidade.status === 'Aberta' ? 'bg-green-100 text-green-800' : 
                          oportunidade.status === 'Fechada' ? 'bg-yellow-100 text-yellow-800' : 
                          oportunidade.status === 'Encerrada' ? 'bg-gray-100 text-gray-800' :
                          'bg-red-100 text-red-800'
                        }`}>
                          {oportunidade.status}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-cursor-text-secondary">
                        {oportunidade.total_recomendacoes || 0}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm">
                        <Link to={`/instituicao-contratante/oportunidades/${oportunidade.id}`} className="text-cursor-primary hover:underline">
                          Detalhes
                        </Link>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {oportunidades.length > 5 && (
                <div className="p-4 text-right">
                  <Link to="/instituicao-contratante/oportunidades" className="text-cursor-primary text-sm hover:underline">
                    Ver todas ({oportunidades.length})
                  </Link>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default DashboardInstituicaoContratante;
